use std::collections::HashMap;
use std::fs;
use std::path::Path;

pub fn load_user_scores(path: &str) -> Result<HashMap<String, i64>, String> {
    let contents = match fs::read_to_string(Path::new(path)) {
        Ok(c) => c,
        Err(e) => return Err(format!("Failed to read file: {}", e)),
    };
    let mut scores: HashMap<String, i64> = HashMap::new();
    for line in contents.lines() {
        if line.trim().is_empty() {
            continue;
        }
        let parts: Vec<&str> = line.split(',').collect();
        if parts.len() != 2 {
            return Err(format!("Invalid line: {}", line));
        }
        let name = parts[0].trim();
        let score = match parts[1].trim().parse::<i64>() {
            Ok(s) => s,
            Err(_) => return Err(format!("Invalid score for {}: {}", name, parts[1].trim())),
        };
        if scores.contains_key(name) {
            let existing = scores.get_mut(name).unwrap();
            *existing += score;
        } else {
            scores.insert(name.to_string(), score);
        }
    }
    return scores;
}
