```rust
pub struct TaskQueue {
    tasks: Vec<Task>,
    max_retries: u32,
    timeout_ms: u64,
    is_paused: bool,
}

impl TaskQueue {
    pub fn new(max_retries: u32, timeout_ms: u64) -> Self {
        Self {
            tasks: Vec::new(),
            max_retries: max_retries,
            timeout_ms: timeout_ms,
            is_paused: false,
        }
    }

    pub fn pending_count(&self) -> usize {
        let mut count = 0;
        for task in &self.tasks {
            match task.status {
                TaskStatus::Pending => {
                    count += 1;
                }
                _ => {}
            }
        }
        count
    }

    pub fn has_failures(&self) -> bool {
        for task in &self.tasks {
            if task.status == TaskStatus::Failed {
                return true;
            }
        }
        return false;
    }

    pub fn retry_failed(&mut self) {
        let mut to_retry = Vec::new();
        for i in 0..self.tasks.len() {
            if self.tasks[i].status == TaskStatus::Failed {
                if self.tasks[i].retries < self.max_retries {
                    to_retry.push(i);
                }
            }
        }
        for i in to_retry {
            self.tasks[i].status = TaskStatus::Pending;
            self.tasks[i].retries += 1;
        }
    }

    pub fn is_complete(&self) -> bool {
        if self.tasks.is_empty() {
            return false;
        }
        for task in &self.tasks {
            match task.status {
                TaskStatus::Pending | TaskStatus::Running => return false,
                _ => {}
            }
        }
        return true;
    }
}
