Make this more idiomatic Rust. It's a small utility that processes log entries:

```rust
use std::collections::HashMap;

#[derive(Clone, Debug)]
pub struct LogEntry {
    pub timestamp: u64,
    pub level: String,
    pub message: String,
    pub source: Option<String>,
}

pub fn filter_errors(entries: &Vec<LogEntry>) -> Vec<LogEntry> {
    let mut result = Vec::new();
    for entry in entries.iter() {
        if entry.level == String::from("ERROR") {
            result.push(entry.clone());
        }
    }
    result
}

pub fn count_by_level(entries: &Vec<LogEntry>) -> HashMap<String, usize> {
    let mut counts = HashMap::new();
    for entry in entries.iter() {
        let count = counts.get(&entry.level);
        match count {
            Some(c) => {
                counts.insert(entry.level.clone(), c + 1);
            }
            None => {
                counts.insert(entry.level.clone(), 1);
            }
        }
    }
    counts
}

pub fn get_sources(entries: &Vec<LogEntry>) -> Vec<String> {
    let mut sources = Vec::new();
    for entry in entries.iter() {
        match &entry.source {
            Some(s) => {
                let mut found = false;
                for existing in &sources {
                    if existing == s {
                        found = true;
                        break;
                    }
                }
                if !found {
                    sources.push(s.clone());
                }
            }
            None => {}
        }
    }
    sources
}

pub fn format_entry(entry: &LogEntry) -> String {
    let source_str;
    match &entry.source {
        Some(s) => source_str = format!(" [{}]", s),
        None => source_str = String::from(""),
    };
    let mut result = String::new();
    result.push_str(&format!("[{}]", entry.timestamp));
    result.push_str(&format!(" {}", entry.level));
    result.push_str(&source_str);
    result.push_str(&format!(" {}", entry.message));
    result
}
